                        { id: 44, text: "I demand ________ the person who is in charge of handling customers' complaints here.", answer: "to see", type: 'multiple_choice', options: ["to be seen", "having seen", "seeing", "to see"] },
                        { id: 45, text: "I'm sorry that I didn't remember ________ $100 from you, but I promise ________ you back as soon as I get my salary next week.", answer: "borrowing – to pay", type: 'multiple_choice', options: ["borrowing – to pay", "to borrow – having paid", "having borrowed – pay", "to be borrowing – paying"] },
                        { id: 46, text: "Upon arriving at the flat ________ it, we noticed that it hadn't been decorated as tastefully as the estate agent had led us ________.", answer: "to view – to believe", type: 'multiple_choice', options: ["to view – to believe", "to be viewing – believed", "having viewed – believe", "viewing – to have believed"] },
                        { id: 47, text: "I'd like ________ your sister ________ my daughter's wedding dress as she's such a talented seamstress.", answer: "to have – make", type: 'multiple_choice', options: ["having – made", "have – having made", "to be having – making", "to have – make"] },
                        { id: 48, text: "I must remember ________ Frances when I get home to let her ________ about the changes to the schedule.", answer: "to call – know", type: 'multiple_choice', options: ["having called – know", "calling – to know", "to be calling – known", "to call – know"] },
                        { id: 49, text: "Normally she's too proud ________ that she's made a mistake, so it's incredible that we got her ________ in this case.", answer: "to admit – to apologize", type: 'multiple_choice', options: ["to admit – to apologize", "to be admitting – apologize", "to have admitted – apologize", "admitting – having apologized"] }
